import re
from dataclasses import dataclass
from typing import Optional

@dataclass
class InjectionScanResult:
    blocked: bool
    pattern_matched: Optional[str]
    risk_score: float  # 0.0 low risk, 1.0 certain injection

# Layered detection: fast regex first, then semantic (model-based) for borderline cases
_INJECTION_PATTERNS = [
    (re.compile(r'(?i)ignore\s+(all\s+)?(previous|above|prior)\s+instructions'), "ignore_previous", 0.95),
    (re.compile(r'(?i)you\s+are\s+now\s+(a\s+)?\w+\s+without\s+restrictions'), "persona_override", 0.90),
    (re.compile(r'(?i)(system\s+prompt|instructions)\s*:?\s*reveal'), "system_leak", 0.85),
    (re.compile(r'(?i)print\s+(all\s+)?(your\s+)?(instructions|prompt|context)'), "context_extract", 0.85),
    (re.compile(r'(?i)(jailbreak|DAN|do anything now)'), "jailbreak_keyword", 0.70),
]

_BLOCK_THRESHOLD = 0.80

def scan_for_injection(text: str) -> InjectionScanResult:
    max_score = 0.0
    matched_pattern = None

    for pattern, name, score in _INJECTION_PATTERNS:
        if pattern.search(text):
            if score > max_score:
                max_score = score
                matched_pattern = name

    blocked = max_score >= _BLOCK_THRESHOLD
    return InjectionScanResult(
        blocked=blocked,
        pattern_matched=matched_pattern,
        risk_score=max_score,
    )

def scan_rag_chunk(chunk: str, source_url: str) -> InjectionScanResult:
    result = scan_for_injection(chunk)
    if result.blocked:
        # Log: external document attempting injection from source_url
        raise SecurityError(
            f"Injection detected in RAG chunk from {source_url}: "
            f"pattern={result.pattern_matched}, score={result.risk_score:.2f}"
        )
    return result

class SecurityError(Exception):
    pass

import functools
from typing import Optional
import boto3

# Thin wrapper that caches secrets for TTL_SECONDS and audits every fetch
_cache: dict = {}
TTL_SECONDS = 300

def get_secret(secret_id: str, caller_service: str) -> str:
    import time
    cached = _cache.get(secret_id)
    if cached and time.monotonic() - cached["ts"] < TTL_SECONDS:
        return cached["value"]

    client = boto3.client("secretsmanager")
    response = client.get_secret_value(SecretId=secret_id)
    value = response["SecretString"]

    _cache[secret_id] = {"value": value, "ts": time.monotonic()}

    # Emit audit event — do NOT log the value itself
    print(f"AUDIT secret_access secret_id={secret_id} caller={caller_service}")
    return value

# NFR: secrets must not appear in logs
def safe_log_config(config: dict) -> dict:
    REDACT_KEYS = {"api_key", "password", "secret", "token", "credential"}
    return {
        k: "***REDACTED***" if any(r in k.lower() for r in REDACT_KEYS) else v
        for k, v in config.items()
    }
